import React, { useEffect, useState } from 'react'
import { seasonService, expenseService } from '../../services/api'
import '../../styles/dashboard.css'

const categories = [
  { id: 1, name: 'Thức ăn' },
  { id: 2, name: 'Thuốc / Vi sinh' },
  { id: 3, name: 'Điện nước' },
]

const ManagerExpenses = () => {
  const [seasons, setSeasons] = useState([])
  const [selectedSeason, setSelectedSeason] = useState(null)
  const [amount, setAmount] = useState('')
  const [categoryId, setCategoryId] = useState(1)
  const [note, setNote] = useState('')
  const [expenses, setExpenses] = useState([])
  const [stats, setStats] = useState({ total_amount: 0, total_expenses: 0, avg_amount: 0 })
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    fetchSeasons()
  }, [])

  useEffect(() => {
    if (selectedSeason) {
      fetchExpenses(selectedSeason)
      fetchStats(selectedSeason)
    }
  }, [selectedSeason])

  const fetchSeasons = async () => {
    try {
      const res = await seasonService.getAllSeasons()
      if (res?.data?.data) {
        setSeasons(res.data.data)
        if (res.data.data.length > 0) setSelectedSeason(res.data.data[0].season_id)
      }
    } catch (err) {
      console.error(err)
    }
  }

  const fetchExpenses = async (seasonId) => {
    try {
      setLoading(true)
      const res = await expenseService.getExpensesBySeasonId(seasonId)
      setExpenses(res?.data?.data || [])
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  const fetchStats = async (seasonId) => {
    try {
      const res = await expenseService.getExpenseStats(seasonId)
      setStats(res?.data?.data || { total_amount: 0, total_expenses: 0, avg_amount: 0 })
    } catch (err) {
      console.error(err)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!selectedSeason) return alert('Chọn mùa vụ')
    if (!amount || Number(amount) <= 0) return alert('Số tiền không hợp lệ')

    try {
      setLoading(true)
      const payload = {
        seasonId: selectedSeason,
        categoryId,
        description: note,
        amount: Number(amount),
      }
      await expenseService.createExpense(payload)
      setAmount('')
      setNote('')
      fetchExpenses(selectedSeason)
      fetchStats(selectedSeason)
      alert('Ghi nhận chi phí thành công')
    } catch (err) {
      console.error(err)
      alert(err?.response?.data?.message || 'Lỗi khi ghi nhận chi phí')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="dashboard-container">
      <h2>Quản lý Chi phí (Manager)</h2>

      <div className="card" style={{ marginBottom: 20 }}>
        <h3>Thêm chi phí</h3>
        <form onSubmit={handleSubmit} style={{ display: 'flex', gap: 12, alignItems: 'flex-end' }}>
          <div style={{ flex: 1 }}>
            <label>Mùa vụ</label>
            <select value={selectedSeason || ''} onChange={(e) => setSelectedSeason(e.target.value)} className="input">
              {seasons.map((s) => (
                <option key={s.season_id} value={s.season_id}>{s.season_name}</option>
              ))}
            </select>
          </div>

          <div style={{ width: 180 }}>
            <label>Danh mục</label>
            <select value={categoryId} onChange={(e) => setCategoryId(Number(e.target.value))} className="input">
              {categories.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>

          <div style={{ width: 200 }}>
            <label>Số tiền (VND)</label>
            <input className="input" type="number" value={amount} onChange={(e) => setAmount(e.target.value)} />
          </div>

          <div style={{ flex: 1 }}>
            <label>Ghi chú</label>
            <input className="input" value={note} onChange={(e) => setNote(e.target.value)} />
          </div>

          <div style={{ width: 140 }}>
            <button className="btn btn-primary" type="submit" disabled={loading} style={{ width: '100%' }}>
              {loading ? 'Đang lưu...' : 'Ghi nhận'}
            </button>
          </div>
        </form>
      </div>

      <div className="card">
        <h3>Tổng chi phí theo mùa vụ</h3>
        <div style={{ display: 'flex', gap: 20 }}>
          <div style={{ flex: 1 }}>
            <strong>Tổng tiền:</strong> {Number(stats.total_amount || 0).toLocaleString('vi-VN')} VND
          </div>
          <div style={{ flex: 1 }}>
            <strong>Số lần ghi nhận:</strong> {stats.total_expenses}
          </div>
          <div style={{ flex: 1 }}>
            <strong>Giá trị TB:</strong> {Number(stats.avg_amount || 0).toLocaleString('vi-VN')} VND
          </div>
        </div>

        <h4 style={{ marginTop: 16 }}>Chi tiết chi phí</h4>
        <table className="table">
          <thead>
            <tr>
              <th>Ngày</th>
              <th>Danh mục</th>
              <th>Số tiền</th>
              <th>Ghi chú</th>
            </tr>
          </thead>
          <tbody>
            {loading && <tr><td colSpan={4}>Đang tải...</td></tr>}
            {!loading && expenses.length === 0 && <tr><td colSpan={4}>Chưa có dữ liệu</td></tr>}
            {!loading && expenses.map((ex) => (
              <tr key={ex.expense_id}>
                <td>{ex.expense_date}</td>
                <td>{ex.category_name || 'Khác'}</td>
                <td>{Number(ex.amount).toLocaleString('vi-VN')}</td>
                <td>{ex.note}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

export default ManagerExpenses
